import { useEffect, useState } from 'react';
import api from '../api/client';

export default function TicketList({ refreshKey = 0 }) {
  const [tickets, setTickets] = useState([]);
  const [search, setSearch] = useState('');
  const [status, setStatus] = useState('');
  const [page, setPage] = useState(1);
  const [count, setCount] = useState(0);
  const [nextPage, setNextPage] = useState(null);
  const [previousPage, setPreviousPage] = useState(null);

  const loadTickets = async () => {
    try {
      const params = { page };

      if (search) params.search = search;
      if (status) params.status = status;

      const res = await api.get('/tickets/', { params });

      const data = res.data;
      setTickets(data.results || []);
      setCount(data.count || 0);
      setNextPage(data.next);
      setPreviousPage(data.previous);
    } catch (err) {
      console.error('Failed to load tickets', err);
    }
  };

  useEffect(() => {
    loadTickets();
  }, [refreshKey, page]);

  const handleApply = () => {
    setPage(1);
    loadTickets();
  };

  const handleExport = async () => {
    try {
      const params = {};
      if (search) params.search = search;
      if (status) params.status = status;

      const res = await api.get('/tickets/export_excel/', {
        params,
        responseType: 'blob',
      });

      const url = window.URL.createObjectURL(new Blob([res.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', 'tickets.xlsx');
      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch (err) {
      console.error('Export failed', err);
    }
  };

  const totalPages = Math.ceil(count / 8);

  return (
    <div>
      <div className="row mb-3">
        <div className="col-md-5">
          <input
            type="text"
            className="form-control"
            placeholder="Search by ticket / subject"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>

        <div className="col-md-4">
          <select
            className="form-select"
            value={status}
            onChange={(e) => setStatus(e.target.value)}
          >
            <option value="">All Status</option>
            <option value="Open">Open</option>
            <option value="In Progress">In Progress</option>
            <option value="Resolved by Support">Resolved by Support</option>
            <option value="Sent to Developer">Sent to Developer</option>
            <option value="Developer In Progress">Developer In Progress</option>
            <option value="Closed">Closed</option>
            <option value="Reopened">Reopened</option>
          </select>
        </div>

        <div className="col-md-1 d-grid">
          <button className="btn btn-primary" onClick={handleApply}>
            Apply
          </button>
        </div>

        <div className="col-md-2 d-grid">
          <button className="btn btn-success" onClick={handleExport}>
            Export Excel
          </button>
        </div>
      </div>

      <div className="table-responsive">
        <table className="table table-bordered table-striped">
          <thead>
            <tr>
              <th>Ticket ID</th>
              <th>Department</th>
              <th>Division</th>
              <th>Module</th>
              <th>Submodule</th>
              <th>Subject</th>
              <th>Status</th>
              <th>Closed Date</th>
              <th>Decision</th>
              <th>Created</th>
            </tr>
          </thead>
          <tbody>
            {tickets.length ? (
              tickets.map((ticket) => (
                <tr key={ticket.id}>
                  <td>{ticket.ticket_id}</td>
                  <td>{ticket.department_name || ''}</td>
                  <td>{ticket.division_name || ''}</td>
                  <td>{ticket.module_name || ''}</td>
                  <td>{ticket.submodule_name || ''}</td>
                  <td>{ticket.subject}</td>
                  <td>{ticket.status}</td>
                  <td>
  {ticket.closed_at
    ? new Date(ticket.closed_at).toLocaleString()
    : ''}
</td>
                  <td>{ticket.support_decision}</td>
                  <td>
                    {ticket.created_at
                      ? new Date(ticket.created_at).toLocaleString()
                      : ''}
                  </td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan="9" className="text-center">
                  No tickets found
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      <div className="d-flex justify-content-between align-items-center mt-3">
        <div>
          Total Tickets: <strong>{count}</strong>
        </div>

        <div className="d-flex align-items-center gap-2">
          <button
            className="btn btn-outline-secondary"
            disabled={!previousPage}
            onClick={() => setPage((prev) => prev - 1)}
          >
            Previous
          </button>

          <span>
            Page <strong>{page}</strong> of <strong>{totalPages || 1}</strong>
          </span>

          <button
            className="btn btn-outline-secondary"
            disabled={!nextPage}
            onClick={() => setPage((prev) => prev + 1)}
          >
            Next
          </button>
        </div>
      </div>
    </div>
  );
}
